timedatectl set-ntp true; wipefs -a /dev/nvme0n1; echo -e "g\nn\n1\n\n+512M\nt\n1\n1\nn\n2\n\n\nw" | fdisk /dev/nvme0n1; mkfs.fat -F32 /dev/nvme0n1p1; mkfs.ext4 /dev/nvme0n1p2; mount /dev/nvme0n1p2 /mnt; mount --mkdir /dev/nvme0n1p1 /mnt/boot; GPU=$(lspci | grep -qi nvidia && echo "nvidia-dkms nvidia-utils linux-headers" || (lspci | grep -qi amd && echo "xf86-video-amdgpu mesa" || echo "mesa")); pacstrap -K /mnt base linux linux-firmware grub efibootmgr git sudo networkmanager base-devel xorg-server xorg-xinit i3-wm i3status dmenu kitty nano $GPU; genfstab -U /mnt >> /mnt/etc/fstab; arch-chroot /mnt bash -c "systemctl enable NetworkManager; grub-install --target=x86_64-efi --efi-directory=/boot --bootloader-id=GRUB; grub-mkconfig -o /boot/grub/grub.cfg; useradd -m -G wheel natek; echo 'natek:natek' | chpasswd; echo 'root:root' | chpasswd; echo '%wheel ALL=(ALL) NOPASSWD: ALL' >> /etc/sudoers; echo 'exec i3' > /home/natek/.xinitrc; chown natek:natek /home/natek/.xinitrc"
